/// Chunk text for RAG retrieval, ensuring every chunk carries a `heading_path`.
///
/// Delegates to `chunk_text` using the caller's config (defaulting to
/// `ChunkerType.Markdown` when the config uses the default `Text` type, so that
/// heading hierarchy is resolved).  After chunking, derives
/// `ChunkMetadata.heading_path` from each chunk's `heading_context`.
///
///   underlying splitter; use `ChunkerType.Markdown` for documents with ATX
///   headings.
///
/// **Returns:**
///
/// A `ChunkingResult` where every chunk's `heading_path` is populated from its
/// `heading_context` (empty when the chunk is not under any heading).
///
/// **Errors:**
///
/// Propagates any error from the underlying chunker (e.g. invalid overlap).
pub fn chunk_for_rag(text: []const u8, config: []const u8) XbergError![]u8 {
    const text_z = try std.fmt.allocPrintSentinel(
        std.heap.c_allocator, "{s}", .{text}, 0);
    defer std.heap.c_allocator.free(text_z);
    const config_z = try std.fmt.allocPrintSentinel(
        std.heap.c_allocator, "{s}", .{config}, 0);
    defer std.heap.c_allocator.free(config_z);
    const config_handle = c.xberg_chunking_config_from_json(config_z);
    if (config_handle == null) return _error_with_message(XbergError);
    defer c.xberg_chunking_config_free(config_handle);
    const _result = c.xberg_chunk_for_rag(text_z, config_handle);
    if (c.xberg_last_error_code() != 0) {
        return _error_with_message(XbergError);
    }
    if (_result == null) {
        return _error_with_message(XbergError);
    }
    return blk: {
        const _json_ptr = c.xberg_chunking_result_to_json(_result.?);
        c.xberg_chunking_result_free(_result.?);
        if (_json_ptr == null) return _first_error(XbergError); // FFI to_json returned NULL — surface first declared variant rather than crashing on null-slice
        defer _free_string(_json_ptr);
        const slice = std.mem.sliceTo(_json_ptr, 0);
        const owned = try std.heap.c_allocator.dupe(u8, slice);
        break :blk owned;
    }
;
}

