/// Analyze a document and determine the optimal chunking strategy.
///
/// Decision logic (in priority order):
///
/// 1. If user provides `disable_chunking` → no chunking
/// 2. If user provides page_ranges → use user overrides
/// 3. If chunking is not enabled → no chunking
/// 4. If format doesn't support chunking → no chunking
/// 5. If file is small (below both thresholds) and not force_chunking → no chunking
/// 6. If PDF has a substantial text layer AND !force_ocr → no chunking
///    *(only when `heuristics-pdf` feature is enabled; otherwise skipped)*
///
/// 7. Otherwise → chunk the document
///
/// **Errors:**
///
/// Returns an error only when the `heuristics-pdf` feature is active and
/// the PDF text-layer analysis itself returns a hard error.  In all other
/// cases the function returns a `ChunkingDecision`.
pub fn analyze_document(metadata: []const u8, config: []const u8, document_bytes: ?[]const u8) XbergError!ChunkingDecision {
    const metadata_z = try std.fmt.allocPrintSentinel(
        std.heap.c_allocator, "{s}", .{metadata}, 0);
    defer std.heap.c_allocator.free(metadata_z);
    const metadata_handle = c.xberg_document_metadata_from_json(metadata_z);
    if (metadata_handle == null) return _error_with_message(XbergError);
    defer c.xberg_document_metadata_free(metadata_handle);
    const config_z = try std.fmt.allocPrintSentinel(
        std.heap.c_allocator, "{s}", .{config}, 0);
    defer std.heap.c_allocator.free(config_z);
    const config_handle = c.xberg_heuristics_config_from_json(config_z);
    if (config_handle == null) return _error_with_message(XbergError);
    defer c.xberg_heuristics_config_free(config_handle);
    const _result = c.xberg_analyze_document(metadata_handle, config_handle, document_bytes.ptr, document_bytes.len);
    if (c.xberg_last_error_code() != 0) {
        return _error_with_message(XbergError);
    }
    return ChunkingDecision{ ._handle = _result.? };
}

