    const result_z = try std.fmt.allocPrintSentinel(
        std.heap.c_allocator, "{s}", .{result}, 0);
    defer std.heap.c_allocator.free(result_z);
    const result_handle = c.xberg_extraction_result_from_json(result_z);
    if (result_handle == null) return error.InvalidJson;
    defer c.xberg_extraction_result_free(result_handle);
    const thresholds_z = try std.fmt.allocPrintSentinel(
        std.heap.c_allocator, "{s}", .{thresholds}, 0);
    defer std.heap.c_allocator.free(thresholds_z);
    const thresholds_handle = c.xberg_multidoc_thresholds_from_json(thresholds_z);
    if (thresholds_handle == null) return error.InvalidJson;
    defer c.xberg_multidoc_thresholds_free(thresholds_handle);
    const _result = c.xberg_boundaries_from_extraction_result(result_handle, thresholds_handle);
    const _result_len = c.xberg_boundaries_from_extraction_result_len(result_handle, thresholds_handle);
    return blk: {
        const slice = _result[0.._result_len];
        const owned = try std.heap.c_allocator.dupe(u8, slice);
        _free_string(_result);
        break :blk owned;
    }
;
}

