/// Render a single PDF page to PNG bytes.
///
/// Returns raw PNG-encoded bytes for the specified page at the given DPI.
/// Uses pdf_oxide with tiny-skia for pure-Rust rendering.
///
/// For pages with extreme dimensions (very wide vector diagrams, etc.) the
/// effective DPI may be automatically reduced to avoid rasterizer failure.
/// A warning is logged when this happens.
///
/// **Errors:**
///
/// Returns `XbergError.Parsing` if the PDF cannot be opened, authenticated,
/// or rendered, or if `page_index` is out of range.
pub fn render_pdf_page_to_png(pdf_bytes: []const u8, page_index: u64, dpi: ?i32, password: ?[]const u8) XbergError![]u8 {
    const password_z: ?[:0]u8 = if (password) |v| try std.fmt.allocPrintSentinel(
        std.heap.c_allocator, "{s}", .{v}, 0) else null;
    defer if (password_z) |z| std.heap.c_allocator.free(z);
    var _out_ptr: [*c]u8 = undefined;
    var _out_len: usize = 0;
    var _out_cap: usize = 0;
    _ = c.xberg_render_pdf_page_to_png(pdf_bytes.ptr, pdf_bytes.len, page_index, if (dpi) |v| v else std.math.maxInt(i32), if (password_z) |z| z.ptr else null, &_out_ptr, &_out_len, &_out_cap);
    if (c.xberg_last_error_code() != 0) {
        return _error_with_message(XbergError);
    }
    const _owned = try std.heap.c_allocator.dupe(u8, _out_ptr[0.._out_len]);
    c.xberg_free_bytes(_out_ptr, _out_len, _out_cap);
    return _owned;
}

