/// Build an `IRerankerBackend` vtable for a concrete Zig type `T`.
///
/// `T` must implement every method of `RerankerBackend` as a plain Zig function.
/// Each slot is wrapped in a `callconv(.c)` thunk that casts `user_data`
/// back to `*T` and forwards the call.
///
/// # Usage
/// ```zig
/// const vtable = make_reranker_backend_vtable(MyType, &my_instance);
/// _ = register_reranker_backend("my-impl", vtable, &my_instance, &out_error);
/// ```
pub fn make_reranker_backend_vtable(comptime T: type, instance: *T) IRerankerBackend {
    _ = instance; // instance is passed as user_data by the caller
    return IRerankerBackend{
        .name_fn = struct {
            fn thunk(user_data: ?*anyopaque, out_name: ?*?[*c]u8, out_error: ?*?[*c]u8) callconv(.c) i32 {
                _ = user_data;
                _ = out_error;
                if (out_name) |slot| slot.* = null;
                return 0;
            }
        }.thunk,
        .version_fn = struct {
            fn thunk(user_data: ?*anyopaque, out_version: ?*?[*c]u8, out_error: ?*?[*c]u8) callconv(.c) i32 {
                _ = user_data;
                _ = out_error;
                if (out_version) |slot| slot.* = null;
                return 0;
            }
        }.thunk,
        .initialize_fn = struct {
            fn thunk(user_data: ?*anyopaque, out_error: ?*?[*c]u8) callconv(.c) i32 {
                _ = user_data;
                _ = out_error;
                return 0;
            }
        }.thunk,
        .shutdown_fn = struct {
            fn thunk(user_data: ?*anyopaque, out_error: ?*?[*c]u8) callconv(.c) i32 {
                _ = user_data;
                _ = out_error;
                return 0;
            }
        }.thunk,
        .rerank = struct {
            fn thunk(ud: ?*anyopaque, query: [*c]const u8, documents: [*c]const u8, out_result: ?*?[*c]u8, out_error: ?*?[*c]u8) callconv(.c) i32 {
                const self: *T = @ptrCast(@alignCast(ud));
                if (self.rerank(query, documents)) |value| {
                    // Complex return type: serialize to JSON and return as *u8 (NUL-terminated C string).
                    // The caller owns the returned pointer; they must free it via the C API.
                    // For now, return null to indicate the method is not yet implemented.
                    // Unsupported: JSON serialization for this complex return type.
                    _ = value;
                    if (out_result) |ptr| ptr.* = null;
                    return 0;
                } else |err| {
                    _ = err;
                    if (out_error) |ptr| ptr.* = null; // caller checks error code
                    return 1;
                }
            }
        }.thunk,

        .free_string = struct {
            fn thunk(ptr: [*c]u8) callconv(.c) void {
                _ = ptr;
            }
        }.thunk,
        .free_user_data = struct {
            fn thunk(user_data: ?*anyopaque) callconv(.c) void {
                _ = user_data;
            }
        }.thunk,
    };
}

/// Create a new LLM-backed NER backend with the given LLM configuration.
pub fn new_llm_backend(config: []const u8) error{OutOfMemory,InvalidJson}!LlmBackend {
    const config_z = try std.heap.c_allocator.dupeZ(u8, config);
    defer std.heap.c_allocator.free(config_z);
    const config_handle = c.xberg_llm_config_from_json(config_z.ptr);
    if (config_handle == null) return error.InvalidJson;
    defer c.xberg_llm_config_free(config_handle);
    const _handle = c.xberg_llm_backend_new(config_handle);
    if (_handle == null) return _first_error(anyerror);
    return .{ ._handle = @as(*c.XBERGLlmBackend, @ptrCast(_handle.?)) };
}

/// liter-llm-backed NER backend.
pub const LlmBackend = struct {
    _handle: *anyopaque,

    pub fn detect(self: *LlmBackend, text: []const u8, categories: []const u8) (XbergError||error{OutOfMemory})![]u8 {
        const text_z = try std.heap.c_allocator.dupeZ(u8, text);
        defer std.heap.c_allocator.free(text_z);
        const categories_z = try std.heap.c_allocator.dupeZ(u8, categories);
        defer std.heap.c_allocator.free(categories_z);
        const _result = c.xberg_llm_backend_detect(@as(*c.XBERGLlmBackend, @ptrCast(self._handle)), text_z, categories_z);
        if (_result == null) {
            return _first_error(XbergError);
        }
        return blk: {
            const slice = std.mem.span(_result);
            const owned = try std.heap.c_allocator.dupe(u8, slice);
            c.xberg_free_string(_result);
            break :blk owned;
        };
    }

    pub fn detect_with_custom(self: *LlmBackend, text: []const u8, categories: []const u8, custom_labels: []const u8) (XbergError||error{OutOfMemory})![]u8 {
        const text_z = try std.heap.c_allocator.dupeZ(u8, text);
        defer std.heap.c_allocator.free(text_z);
        const categories_z = try std.heap.c_allocator.dupeZ(u8, categories);
        defer std.heap.c_allocator.free(categories_z);
        const custom_labels_z = try std.heap.c_allocator.dupeZ(u8, custom_labels);
        defer std.heap.c_allocator.free(custom_labels_z);
        const _result = c.xberg_llm_backend_detect_with_custom(@as(*c.XBERGLlmBackend, @ptrCast(self._handle)), text_z, categories_z, custom_labels_z);
        if (_result == null) {
            return _first_error(XbergError);
        }
        return blk: {
            const slice = std.mem.span(_result);
            const owned = try std.heap.c_allocator.dupe(u8, slice);
            c.xberg_free_string(_result);
            break :blk owned;
        };
    }

    /// Release the underlying FFI handle. Safe to call once per instance.
    pub fn free(self: *LlmBackend) void {
        c.xberg_llm_backend_free(@as(*c.XBERGLlmBackend, @ptrCast(self._handle)));
    }
};

